import {
  rectangle, polygon, segment,
  union, dilate, render,
} from '../../src/index.js';

// Bare-bones canyon silhouette — V-shape valley walls + sky.
// Scene completion should add terrain-canyon primitive + river + distant peaks + birds.

// Left canyon wall (descending to floor)
const leftWall = polygon([
  [-0.80,  0.50],
  [-0.30, -0.30],
  [-0.20, -0.30],
  [-0.70,  0.50],
]);

// Right canyon wall (mirror)
const rightWall = polygon([
  [ 0.80,  0.50],
  [ 0.30, -0.30],
  [ 0.20, -0.30],
  [ 0.70,  0.50],
]);

// Canyon floor
const floor = rectangle([0.50, 0.05], [0, -0.34]);

// Sky
const sky = rectangle([1.6, 0.80], [0, 0.20]);

const layers = [
  { sdf: sky,       color: [195, 168, 130] },
  { sdf: dilate(leftWall, 0.014),  color: [70, 35, 25] },
  { sdf: leftWall,                 color: [180, 90, 50] },
  { sdf: dilate(rightWall, 0.014), color: [70, 35, 25] },
  { sdf: rightWall,                color: [180, 90, 50] },
  { sdf: floor,                    color: [140, 80, 50] },
];
const canvas = document.getElementById('c');
const ctx = canvas.getContext('2d');
render.silhouette(ctx, layers, {
  view: 1.4,
  background: { top: [230, 195, 140], bottom: [240, 220, 175] },
});
```

**Composition notes**: Bare canyon silhouette — V-shape walls + floor + sky. Red-sandstone palette suggests Grand Canyon style. Scene completion should add: `terrain-canyon` primitive as hero terrain (Atlas has it), distant peaks (rock-boulder × 2-3 far away), birds (scatter in box3 sky), river segment along floor, cinematic atmosphere (postFx + DoF + faint atmospheric fog). Nature-class peer-level world.
